def restoreIpAddresses(s):
    result = []
    n = len(s)

    def isValid(segment):
        return 0 <= int(segment) <= 255 and (segment == "0" or not segment.startswith("0"))

    def backtrack(index, dots, current_ip):
        if dots == 4:
            if index == n:
                result.append(current_ip[:-1])
            return

        for i in range(index, min(index + 3, n)):
            segment = s[index:i+1]
            if isValid(segment):
                backtrack(i + 1, dots + 1, current_ip + segment + ".")

    backtrack(0, 0, "")
    return result
